        await LoadLogs(); // 最新状態を再読み込み
    }

    private async Task DeleteRecord(PlantRecord record)
    {
        DbContext.PlantRecords.Remove(record);
        await DbContext.SaveChangesAsync();
        await LoadLogs();
    }

